const logs = $input.all().map(i => i.json);
const chatId = $('Execute Workflow Trigger').first().json.chatId;

function getProp(props, key, type) {
  const p = props?.[key];
  if (!p) return '';
  if (type === 'title') return p.title?.[0]?.plain_text || '';
  if (type === 'text') return p.rich_text?.[0]?.plain_text || '';
  if (type === 'number') return p.number || 0;
  if (type === 'date') return p.date?.start || '';
  return '';
}

// Get last 3 logs per project
const logsByProject = {};
logs.forEach(log => {
  const projRel = log.properties?.project_id?.relation || [];
  const projId = projRel[0]?.id || 'unknown';
  if (!logsByProject[projId]) logsByProject[projId] = [];
  if (logsByProject[projId].length < 3) {
    logsByProject[projId].push({
      date: getProp(log.properties, 'log_date', 'date'),
      activity: getProp(log.properties, 'activity_description', 'text'),
      hours: getProp(log.properties, 'hours_spent', 'number')
    });
  }
});

const totalHoursToday = logs
  .filter(l => {
    const d = getProp(l.properties, 'log_date', 'date');
    return d === new Date().toISOString().split('T')[0];
  })
  .reduce((sum, l) => sum + getProp(l.properties, 'hours_spent', 'number'), 0);

if (Object.keys(logsByProject).length === 0) {
  return [{ json: { chatId, skipActivityReport: true } }];
}

let activitySummary = '\n\n📋 <b>AKTIVITAS TERKINI (Per Proyek)</b>\n';
for (const [projId, projLogs] of Object.entries(logsByProject)) {
  if (projLogs.length > 0) {
    activitySummary += `\n🔹 <i>Proyek: ${projId.substring(0, 8)}...</i>\n`;
    projLogs.forEach(l => {
      activitySummary += `  • ${l.date}: ${l.activity.substring(0, 80)}${l.activity.length > 80 ? '...' : ''} (${l.hours}j)\n`;
    });
  }
}
activitySummary += `\n⏱ <b>Total Jam Hari Ini:</b> ${totalHoursToday} jam`;

return [{ json: { chatId, activitySummary, totalHoursToday } }];
